SELECT 
FROM pet_health_record r
LEFT JOIN pet p ON r.pet_id = p.id
LEFT JOIN user u ON p.user_id = u.id


        AND (p.name LIKE CONCAT('%',#{keyword},'%') OR u.username LIKE CONCAT('%',#{keyword},'%'))


        AND r.risk_level = #{riskLevel}


        AND r.inspection_date >= #{startDate}


        AND r.inspection_date <= #{endDate}


ORDER BY r.inspection_date DESC
LIMIT #{offset}, #{pageSize}

SELECT COUNT(*) FROM pet_health_record r
LEFT JOIN pet p ON r.pet_id = p.id
LEFT JOIN user u ON p.user_id = u.id


        AND (p.name LIKE CONCAT('%',#{keyword},'%') OR u.username LIKE CONCAT('%',#{keyword},'%'))


        AND r.risk_level = #{riskLevel}


        AND r.inspection_date >= #{startDate}


        AND r.inspection_date <= #{endDate}

